# -*- coding: utf-8 -*-'''project:task 3 yolo recognition  version:3-1  author:jiayu  date:2024.6.30'''   # 文件头说明# encoding: UTF-8                                                              # 指定源码编码#!/usr/bin/env python2                                                       # shebang，Linux下可直接./运行（实际代码已迁移到Python3）import cv2                                                                   # 图像处理import numpy as np                                                            # 矩阵运算import time                                                                   # 延时/计时import rospy                                                                  # ROS Python接口from pymycobot.mycobot import MyCobot                                         # 机械臂SDKfrom opencv_yolo import yolo                                                  # 自研YOLO封装import math                                                                   # 数学函数（未用，可删）from GrabParams import grabParams                                             # 存放抓取参数import basic                                                                  # 自定义基础函数（如grap、move_to_target_coords）import argparse                                                               # 命令行解析from geometry_msgs.msg import Twist                                           # ROS速度指令from actionlib.action_client import GoalManager                               # 未用，可删import actionlib                                                              # ROS action客户端from move_base_msgs.msg import MoveBaseAction, MoveBaseGoal                   # 导航action接口import re                                                                     # 正则，用于解析目标文件parser = argparse.ArgumentParser(description='manual to this script')         # 命令行参数解析器parser.add_argument("--debug", type=bool, default="True")                     # 是否调试模式args = parser.parse_args()                                                    # 解析结果pub = rospy.Publisher('cmd_vel', Twist, queue_size=1)                         # 发布速度话题move_cmd = Twist()                                                            # 速度指令容器height_bias = grabParams.height_bias                                          # 高度补偿（未用）coords = grabParams.coords_ready                                              # 机械臂待命坐标done = grabParams.done                                                        # 抓取完成标志（未用）CLASSES = ("apple", "clock", "banana", "cat ", "bird ")                       # YOLO类别表mc = MyCobot(grabParams.usb_dev, grabParams.baudrate)                         # 实例化机械臂rospy.init_node('send_goals_python', anonymous=True)                          # 初始化ROS节点outcome1 = 7                                                                  # 当前识别类别序号init_num = 0                                                                  # 已放置次数left = 0                                                                  # 左侧已放置次数right=0num1 = 7                                                                      # 首次识别结果缓存LGJ_speed=80def send_goal(goal_number, goal):                                             # 向move_base发送单点导航目标    client = actionlib.SimpleActionClient('move_base', MoveBaseAction)        # 创建action客户端    client.wait_for_server()                                                  # 等待服务器就绪    goal.target_pose.header.frame_id = "map"                                  # 参考坐标系    goal.target_pose.header.stamp = rospy.Time.now()                          # 时间戳    client.send_goal(goal)                                                    # 发送目标    str_log = "Send NO. %s Goal !!!" % str(goal_number)    rospy.loginfo(str_log)    wait = client.wait_for_result(rospy.Duration.from_sec(60.0))              # 最长等待60s    if not wait:        str_log = "The NO. %s Goal Planning Failed for some reasons" % str(goal_number)        rospy.loginfo(str_log)    else:        str_log = "The NO. %s Goal achieved success !!!" % str(goal_number)        rospy.loginfo(str_log)def read_goal(filename):                                                      # 从txt文件读取导航目标    goal = MoveBaseGoal()    file_to_read = open(filename)    index = 0    for line in file_to_read.readlines():        line = line.strip()        index += 1        if index == 2:                                                        # 第2行：位置            pattern = re.compile(r"(?<=\[).*?(?=\])")            query = pattern.search(line)            listFromLine = query.group().split(',')            goal.target_pose.pose.position.x = float(listFromLine[0])            goal.target_pose.pose.position.y = float(listFromLine[1])        if index == 3:                                                        # 第3行：姿态四元数            pattern = re.compile(r"(?<=\[).*?(?=\])")            query = pattern.search(line)            listFromLine = query.group().split(',')            goal.target_pose.pose.orientation.z = float(listFromLine[2])            goal.target_pose.pose.orientation.w = float(listFromLine[3])    print(goal.target_pose.pose)    return goalcount = 20rate = rospy.Rate(count)  # 20hzdef moveback1(time_seconds, speed):                                           # 后退（speed为负）    print("backward...")    count = 20 * time_seconds    move_cmd = Twist()    while count > 0:        move_cmd.linear.x = speed        pub.publish(move_cmd)        rate.sleep()        count -= 1def moveforward1(time_seconds, speed):                                        # 前进    print("forward...")    count = 20 * time_seconds    move_cmd = Twist()    while count > 0:        move_cmd.linear.x = speed        pub.publish(move_cmd)        rate.sleep()        count -= 1def rotate_to_right1(time_seconds):                                           # 右转（角速度-1 rad/s）    print("rotate_to_right...")    count = 20 * time_seconds    move_cmd = Twist()    while count > 0:        move_cmd.angular.z = -1        pub.publish(move_cmd)        rate.sleep()        count -= 1def rotate_to_left1(time_seconds, speed):                                     # 左转（speed可设）    print("rotate_to_left...")    count = 20 * time_seconds    move_cmd = Twist()    while count > 0:        move_cmd.angular.z = speed        pub.publish(move_cmd)        rate.sleep()        count -= 1def grap(flag):                                # True=闭合抓取，False=张开    if flag:        mc.set_gripper_value(40, 60)             # 设置夹爪闭合到 40（0 最松，100 最紧）        #time.sleep(0.3)                                # 等待 1 s 动作完成    else:        mc.set_gripper_state(0, 60)              # 设置夹爪完全张开        #time.sleep(0.3)def run_put_down(side, seq):    """    side: "left" | "right"   放到哪一侧    seq:  1 | 2               同一侧的序号（落点 1 还是落点 2）    """    #根据 (side, seq) 选取“放置前过渡角度”    if side == "left" and seq == 0:        angles_ready = [-9.93, 46.49, 32.95, -5.8, -167.78, -51.67]#zuo1    elif side == "left" and seq == 1:        angles_ready = [1.31, 48.51, 32.6, -11.51, -167.78, -51.94]#zuo2    elif side == "right" and seq == 0:        angles_ready = [-31.2, 67.85, -0.26, -8.43, -167.95, -56.25]#you1    elif side == "right" and seq == 1:  # right 2        angles_ready = [-40.95, 76.46, -8.87, -10.28, -167.95, -56.33]#you2    angles_home =  [0, 0, 0, 0, 0, 0]    mc.send_angles(angles_ready, LGJ_speed) # 移动到放置过渡姿态    time.sleep(1.5)    grap(False)                      # 张开夹爪，放下物体    print("open")    angle_T=mc.get_angles()    angle_T[1]= angle_T[1]-40    mc.send_angles(angle_T, LGJ_speed)     time.sleep(0.4)    mc.send_angles(angles_home, 80)  # 回到安全角度     time.sleep(1)class Detect_marker(object):                                                  # YOLO识别+抓取逻辑封装    def __init__(self):        super(Detect_marker, self).__init__()        self.mc = MyCobot(grabParams.usb_dev, grabParams.baudrate)        self.mc.power_on()        self.yolo = yolo()        self.x1 = self.x2 = self.y1 = self.y2 = 0                            # 裁剪参数（未用）        self.sum_x1 = self.sum_x2 = self.sum_y2 = self.sum_y1 = 0            # 累计坐标（未用）        self.c_x, self.c_y = grabParams.IMG_SIZE / 2, grabParams.IMG_SIZE / 2  # 图像中心        self.ratio = grabParams.ratio                                          # 像素→毫米比例    def init_mycobot(self):                                                   # 机械臂回到待命姿态        angles = [90, 0, 0, 0, 0, -45]        self.mc.send_angles(angles, 80)        basic.grap(False)                                                     # 张开夹子        #time.sleep(1)    def get_position(self, x, y):                                             # 像素坐标→机械臂基坐标（mm）        wx = wy = 0        if grabParams.grab_direct == "front":            wx = (self.c_y - y) * self.ratio            wy = (self.c_x - x) * self.ratio        elif grabParams.grab_direct == "right":            wx = (self.c_x - x) * self.ratio            wy = (y - self.c_y) * self.ratio        return wx, wy    def transform_frame(self, frame):                                         #  Letterbox到640×640        frame, ratio, (dw, dh) = self.yolo.letterbox(frame, (grabParams.IMG_SIZE, grabParams.IMG_SIZE))        return frame    def transform_frame_128(self, frame):                                     #  Letterbox到128×128（模型输入）        frame, ratio, (dw, dh) = self.yolo.letterbox(frame, (128, 128))        return frame    def obj_detect(self, img):                                                # 单次YOLO推理        x = y = 0        img_ori = img        img_ori = self.transform_frame(img)        img = self.transform_frame_128(img)        net = cv2.dnn.readNetFromONNX("/home/robuster/beetle_ai/scripts/beetle_obj.onnx")        t1 = time.time()        blob = cv2.dnn.blobFromImage(img, 1 / 255.0, (128, 128), [0, 0, 0], swapRB=True, crop=False)        net.setInput(blob)        outputs = net.forward(net.getUnconnectedOutLayersNames())[0]        boxes, classes, scores = self.yolo.yolov5_post_process_simple(outputs)        t2 = time.time()        if boxes is not None:            boxes = boxes * 5                                                     # 128→640放大            self.yolo.draw_single(img_ori, boxes[0], scores[0], classes[0])            left, top, right, bottom = boxes[0]            x = int((left + right) / 2)            y = int((top + bottom) / 2)        cv2.imshow("figure", img_ori)        cv2.waitKey(2)        print("time: " + str(t2 - t1) + "s")        if x + y > 0:            return x, y, classes[0]        else:            return None    def run(self):                                                            # 主入口：亮蓝灯+初始化        self.mc.set_color(0, 0, 255)  # blue, arm is busy        self.init_mycobot()i = 0                                                                         # 主循环计数器while i < 4:                                                                  # 大循环：4次抓取    if i == 0: #行驶到目标位置        time.sleep(1)        detect = Detect_marker()                                              # 创建识别实例        detect.run()        time.sleep(1)        moveforward1(2.65, 0.2)                                                 # 第一段前进        time.sleep(1)        rotate_to_left1(1.3, 1)        #rotate_to_right1(1.3)        time.sleep(1)        moveforward1(1, 0.3)        time.sleep(1)        rotate_to_left1(1.3, -1)#改        time.sleep(1)    i += 1    angles = [90.26, -36.47, 31.28, 11.42, -1.93, -43.68]      #改                                  # 识别前姿态    mc.send_angles(angles, 70)    time.sleep(1.8)    cap = cv2.VideoCapture(2)                                                 # 打开摄像头    while True:                                                               # 边缓慢前进边识别        move_cmd.linear.x = 0.02  #行进速度        move_cmd.linear.z = 0        pub.publish(move_cmd)        retval, frame = cap.read()        frame = cv2.flip(frame, 0)        frame = cv2.flip(frame, 1)        detect_result = detect.obj_detect(frame)        if detect_result is None:            continue        else:            x, y, outcome1 = detect_result            real_x, real_y = detect.get_position(x, y)            print(real_x, real_y)            if (real_x < 25 and real_x > -10) and (real_y > -10 and real_y < 150):                break        if cv2.waitKey(1) & 0xFF == ord('q'):            break    cap.release()    cv2.destroyAllWindows()    angle_T=mc.get_angles()    angle_T[3]=angle_T[3]+30    mc.send_angles(angle_T,80)     time.sleep(0.1)    angles = [89.64, -35.41, -40.51, 77.69, -1.05, -46.93]#改    mc.send_angles(angles, 80)    time.sleep(1.5)    mc.set_gripper_value(40, 60)                                               # 闭合夹子    time.sleep(1)    angle_T=mc.get_angles()    angle_T[1]=angle_T[1]+40    mc.send_angles(angle_T,80)     time.sleep(0.3)    angles = [0, 0, 0, 0, 0, 0]    mc.send_angles(angles, 80)    time.sleep(0.5)    if i == 1:               moveback1(0.5, 0.1)                                                       # 根据i值后退不同距离        time.sleep(1)    elif i == 2:        # moveback1(0.1, -0.1)        time.sleep(1)    elif i == 3:        moveback1(1.1, -0.1)        time.sleep(1)    elif i == 4:        moveback1(2.1, -0.1)        time.sleep(1)    rotate_to_left1(3.22, 0.5)#改    time.sleep(1)    moveback1(2.57, -0.2)    time.sleep(1)#********************************************************************************************************    if init_num == 0:                                                         # 首次放置：放左侧1号位        num1 = outcome1                                                       # 记录首次类别    if num1 == outcome1:        run_put_down("left", left)        init_num += 1        left = left+1        if left >= 2 :            left=left%2            else :        run_put_down("right", right)        right = right+1        if right >=2 :            right=right%2#********************************************************************************************************    #moveforward1(0.6,0.3)    #xia yi ci    if i<4:        moveforward1(2.57,0.2)        time.sleep(2)        if i==1:            rotate_to_left1(3.22,-0.5)#改            time.sleep(1)        elif i==2:            rotate_to_left1(3.22,-0.5)#改            time.sleep(1)        elif i==3 :            rotate_to_left1(3.23,-0.5)#改            time.sleep(1)        mc.set_color(0, 255, 0)  # green, arm is freeangles = [-83.23, -140.53, 140.97, 58.71, -127.61, 5.71]mc.send_angles(angles, 70)time.sleep(1)moveforward1(1.1,0.2)time.sleep(1.5)rotate_to_left1(3.21,0.5)#改time.sleep(1.5)moveforward1(4.5,0.4)  #go1time.sleep(2)rotate_to_left1(1.2,0.5)#改time.sleep(2)moveforward1(1.5,0.4)  #go1time.sleep(2)#send_goal(1, goal3)        